let button=$('.callback button').offset();$(document).scroll(function(){let top=$(window).scrollTop();let height=$(window).height();height=height;let button=$('.callback button').offset();if(button!==undefined){if(top+height-200>=button.top){$('.callback button').addClass('active')}}
let contInfo=$('.callback .cont-info').offset();if(contInfo!==undefined&&top+height>=contInfo.top){$('.callback .cont-info').addClass('active');$('.callback .cont-info').closest('.callback').find('.callback-title').addClass('active');$('.callback .cont-info').closest('.callback').find('form').addClass('active')}})
$(window).scroll(function(){let wh=$(window).height();let wt=$(window).scrollTop();let coord=$('.know-door').offset();let h=$('.know-door').height();if(coord!==undefined){let middle=coord.top+(h/2);if(wh+wt>middle){$('.know-door').each(function(i,item){$(item).addClass('active')})}else{let w=$(window).width();if(w>900){$('.know-door').each(function(i,item){$(item).removeClass('active')})}}}
$('.animate__item').each(function(i,item){let coordAnimate=$(item).offset();if(coordAnimate!==undefined&&wh+wt>coordAnimate.top+150){$(item).removeClass('animate')}})})
