/* Inline Script */
if (document.querySelector(".b-popup-actve")) {
        const btn = document.querySelectorAll(".b-popup-actve");
        btn.forEach(el => {
            el.addEventListener('click', (e) => {
                //e.preventDefault();
                popup.style.display = "flex";
            })
        });
    }

    if (document.querySelector(".modal-popup-wrapper")) {
        const popup = document.querySelector(".modal-popup-wrapper");
        popup.addEventListener('click', (e) => {
            if(e.target.className === 'modal-popup-wrapper') {
                popup.style.display = "none";
            }
        });
    };

